mapper.select:
SELECT n.id, n.sender_id, n.sender_name, n.receiver_id, COALESCE(u.name, u.username) AS receiver_name, n.notice_type, n.source_site_id, s.title AS site_title, n.source_comment_id, n.title, n.summary, n.content, n.is_read, n.create_time, n.read_time FROM sys_notice n LEFT JOIN sys_user u ON n.receiver_id = u.id LEFT JOIN site s ON n.source_site_id = s.id
AND n.receiver_id = #{dto.receiverId}
AND n.notice_type = #{dto.noticeType}
AND n.is_read = #{dto.isRead}
AND (n.title LIKE CONCAT('%', #{dto.keyword}, '%') OR n.summary LIKE CONCAT('%', #{dto.keyword}, '%'))
ORDER BY n.create_time DESC
